from zeep import Client, WSDL
import sys

class InsuranceQuoteClient:
    def __init__(self):
        self.client = Client(WSDL('http://insurance-service.com?wsdl'))

    def get_quote(self, policy_number, customer_name):
        context = self.client.get_context()
        context.set_logging(True)

        soap_body = f"""
            <ns1:getQuote xmlns:ns1="http://insurance-service.com/">
                <policyNumber>{policy_number}</policyNumber>
                <customerName>{customer_name}</customerName>
            </ns1:getQuote>
        """

        response = self.client.service.getQuote(soap_body)
        return response

if __name__ == '__main__':
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")
    client = InsuranceQuoteClient()
    quote = client.get_quote(policy_number, customer_name)
    print(f"Quote response: {quote}")